-- ==============================================================
-- ZOLM v0.5 -> v0.6 KAYIPSIZ VERI GERI YUKLEME (LOSSLESS MERGE)
-- Olusturma Tarihi: 2026-03-06
--
-- Bu script ASLA truncate/drop etmez. Sadece eksik kayitlari ekler.
-- Kapsam: profiles, reports, report_files, supply_orders
-- Kaynak: aizemure_lv129.sql (v0.5)
-- Hedef: mevcut v0.6 veritabani
-- ==============================================================

SET NAMES utf8mb4;
SET @OLD_UNIQUE_CHECKS = @@UNIQUE_CHECKS;
SET @OLD_FOREIGN_KEY_CHECKS = @@FOREIGN_KEY_CHECKS;
SET @OLD_SQL_NOTES = @@SQL_NOTES;
SET UNIQUE_CHECKS = 0;
SET FOREIGN_KEY_CHECKS = 0;
SET SQL_NOTES = 0;

START TRANSACTION;

DROP TABLE IF EXISTS `_v05_profiles_src`;
CREATE TABLE `_v05_profiles_src` (
  `id` bigint unsigned NOT NULL,
  `user_id` bigint unsigned NOT NULL,
  `name` varchar(255) NOT NULL,
  `type` varchar(50) NOT NULL,
  `input_config` longtext,
  `output_config` longtext,
  `ai_prompt` text,
  `sample_input_path` varchar(255),
  `sample_output_path` varchar(255),
  `ai_generated_rules` longtext,
  `is_ai_generated` tinyint(1) NOT NULL DEFAULT 0,
  `status` varchar(20) NOT NULL DEFAULT 'ready',
  `error_message` text,
  `is_default` tinyint(1) NOT NULL DEFAULT 0,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  KEY `idx_v05_profiles_id` (`id`),
  KEY `idx_v05_profiles_key` (`user_id`,`name`,`type`,`created_at`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `_v05_reports_src`;
CREATE TABLE `_v05_reports_src` (
  `id` bigint unsigned NOT NULL,
  `user_id` bigint unsigned NOT NULL,
  `profile_id` bigint unsigned DEFAULT NULL,
  `original_filename` varchar(255) NOT NULL,
  `status` varchar(20) NOT NULL,
  `error_message` text,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  KEY `idx_v05_reports_id` (`id`),
  KEY `idx_v05_reports_key` (`user_id`,`original_filename`,`status`,`created_at`,`updated_at`),
  KEY `idx_v05_reports_profile_id` (`profile_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `_v05_report_files_src`;
CREATE TABLE `_v05_report_files_src` (
  `id` bigint unsigned NOT NULL,
  `report_id` bigint unsigned NOT NULL,
  `filename` varchar(255) NOT NULL,
  `file_path` varchar(255) NOT NULL,
  `sheet_type` varchar(255) DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  KEY `idx_v05_report_files_id` (`id`),
  KEY `idx_v05_report_files_report_id` (`report_id`),
  KEY `idx_v05_report_files_key` (`filename`,`file_path`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `_v05_supply_orders_src`;
CREATE TABLE `_v05_supply_orders_src` (
  `id` bigint unsigned NOT NULL,
  `siparis_no` varchar(50) NOT NULL,
  `kayit_tarihi` date DEFAULT NULL,
  `musteri_adi` varchar(255) NOT NULL,
  `telefon` varchar(30) DEFAULT NULL,
  `adres` text,
  `ilce` varchar(100) DEFAULT NULL,
  `il` varchar(100) DEFAULT NULL,
  `urun_adi` varchar(500) NOT NULL,
  `kategori` varchar(100) DEFAULT NULL,
  `adet` int DEFAULT NULL,
  `soz_tarihi` date DEFAULT NULL,
  `renk_etiketi` varchar(50) DEFAULT NULL,
  `durum` varchar(20) DEFAULT NULL,
  `sebebiyet` varchar(20) DEFAULT NULL,
  `gonderim_tarihi` date DEFAULT NULL,
  `notlar` text,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  KEY `idx_v05_supply_orders_id` (`id`),
  KEY `idx_v05_supply_orders_siparis_no` (`siparis_no`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- ------------------------------
-- 1) v0.5 kaynak verisini staging tablolara yukle
-- ------------------------------




-- ------------------------------
-- 2) Profiles merge (ID carpisma olmadan)
-- ------------------------------
  `user_id`, `name`, `type`, `input_config`, `output_config`,
  `ai_prompt`, `sample_input_path`, `sample_output_path`, `ai_generated_rules`,
  `is_ai_generated`, `status`, `error_message`, `is_default`, `created_at`, `updated_at`
)
SELECT
  s.`user_id`,
  s.`name`,
  CASE
    WHEN s.`type` IN ('production', 'operation', 'custom') THEN s.`type`
    ELSE 'custom'
  END AS `type`,
  CASE
    WHEN s.`input_config` IS NULL THEN NULL
    WHEN JSON_VALID(s.`input_config`) THEN s.`input_config`
    ELSE JSON_QUOTE(s.`input_config`)
  END AS `input_config`,
  CASE
    WHEN s.`output_config` IS NULL THEN NULL
    WHEN JSON_VALID(s.`output_config`) THEN s.`output_config`
    ELSE JSON_QUOTE(s.`output_config`)
  END AS `output_config`,
  s.`ai_prompt`,
  s.`sample_input_path`,
  s.`sample_output_path`,
  CASE
    WHEN s.`ai_generated_rules` IS NULL THEN NULL
    WHEN JSON_VALID(s.`ai_generated_rules`) THEN s.`ai_generated_rules`
    ELSE JSON_QUOTE(s.`ai_generated_rules`)
  END AS `ai_generated_rules`,
  IFNULL(s.`is_ai_generated`, 0),
  CASE
    WHEN s.`status` IN ('draft', 'analyzing', 'ready', 'error') THEN s.`status`
    ELSE 'ready'
  END AS `status`,
  s.`error_message`,
  IFNULL(s.`is_default`, 0),
  s.`created_at`,
  s.`updated_at`
FROM `_v05_profiles_src` s
JOIN `users` u
  ON u.`id` = s.`user_id`
LEFT JOIN `profiles` p
  ON p.`user_id` = s.`user_id`
 AND p.`name` = s.`name`
 AND p.`type` = CASE WHEN s.`type` IN ('production', 'operation', 'custom') THEN s.`type` ELSE 'custom' END
 AND (p.`created_at` <=> s.`created_at`)
WHERE p.`id` IS NULL;

DROP TEMPORARY TABLE IF EXISTS `tmp_profile_map`;
CREATE TEMPORARY TABLE `tmp_profile_map` AS
SELECT
  s.`id` AS `old_profile_id`,
  p.`id` AS `new_profile_id`
FROM `_v05_profiles_src` s
JOIN `profiles` p
  ON p.`user_id` = s.`user_id`
 AND p.`name` = s.`name`
 AND p.`type` = CASE WHEN s.`type` IN ('production', 'operation', 'custom') THEN s.`type` ELSE 'custom' END
 AND (p.`created_at` <=> s.`created_at`);

-- ------------------------------
-- 3) Reports merge (profile_id map ile)
-- ------------------------------
  `user_id`, `profile_id`, `original_filename`, `status`,
  `error_message`, `created_at`, `updated_at`
)
SELECT
  s.`user_id`,
  pm.`new_profile_id` AS `profile_id`,
  s.`original_filename`,
  CASE
    WHEN s.`status` IN ('pending', 'processing', 'success', 'failed') THEN s.`status`
    ELSE 'failed'
  END AS `status`,
  s.`error_message`,
  s.`created_at`,
  s.`updated_at`
FROM `_v05_reports_src` s
JOIN `users` u
  ON u.`id` = s.`user_id`
LEFT JOIN `tmp_profile_map` pm
  ON pm.`old_profile_id` = s.`profile_id`
LEFT JOIN `reports` r
  ON r.`user_id` = s.`user_id`
 AND r.`original_filename` = s.`original_filename`
 AND r.`status` = CASE WHEN s.`status` IN ('pending', 'processing', 'success', 'failed') THEN s.`status` ELSE 'failed' END
 AND (r.`created_at` <=> s.`created_at`)
 AND (r.`updated_at` <=> s.`updated_at`)
 AND (IFNULL(r.`error_message`, '') = IFNULL(s.`error_message`, ''))
WHERE r.`id` IS NULL;

DROP TEMPORARY TABLE IF EXISTS `tmp_report_map`;
CREATE TEMPORARY TABLE `tmp_report_map` AS
SELECT
  s.`id` AS `old_report_id`,
  MIN(r.`id`) AS `new_report_id`
FROM `_v05_reports_src` s
LEFT JOIN `tmp_profile_map` pm
  ON pm.`old_profile_id` = s.`profile_id`
JOIN `reports` r
  ON r.`user_id` = s.`user_id`
 AND r.`original_filename` = s.`original_filename`
 AND r.`status` = CASE WHEN s.`status` IN ('pending', 'processing', 'success', 'failed') THEN s.`status` ELSE 'failed' END
 AND (r.`created_at` <=> s.`created_at`)
 AND (r.`updated_at` <=> s.`updated_at`)
 AND (IFNULL(r.`error_message`, '') = IFNULL(s.`error_message`, ''))
 AND (r.`profile_id` <=> pm.`new_profile_id`)
GROUP BY s.`id`;

-- ------------------------------
-- 4) Report files merge (new report_id map ile)
-- ------------------------------
  `report_id`, `filename`, `file_path`, `sheet_type`, `created_at`, `updated_at`
)
SELECT
  rm.`new_report_id`,
  s.`filename`,
  s.`file_path`,
  s.`sheet_type`,
  s.`created_at`,
  s.`updated_at`
FROM `_v05_report_files_src` s
JOIN `tmp_report_map` rm
  ON rm.`old_report_id` = s.`report_id`
LEFT JOIN `report_files` rf
  ON rf.`report_id` = rm.`new_report_id`
 AND rf.`filename` = s.`filename`
 AND rf.`file_path` = s.`file_path`
 AND (rf.`sheet_type` <=> s.`sheet_type`)
 AND (rf.`created_at` <=> s.`created_at`)
WHERE rf.`id` IS NULL;

-- ------------------------------
-- 5) Supply orders merge
-- NOT: v0.5 modeli siparis_no + urun_adi uniq calisir.
--      v0.6 dump'inda yalniz siparis_no uniq oldugu icin once index duzelt.
-- ------------------------------
SET @idx_single := (
  SELECT COUNT(*)
  FROM information_schema.statistics
  WHERE table_schema = DATABASE()
    AND table_name = 'supply_orders'
    AND index_name = 'supply_orders_siparis_no_unique'
);
SET @sql := IF(
  @idx_single > 0,
  'ALTER TABLE `supply_orders` DROP INDEX `supply_orders_siparis_no_unique`',
  'SELECT 1'
);
PREPARE stmt FROM @sql;
EXECUTE stmt;
DEALLOCATE PREPARE stmt;

SET @idx_pair := (
  SELECT COUNT(*)
  FROM information_schema.statistics
  WHERE table_schema = DATABASE()
    AND table_name = 'supply_orders'
    AND index_name = 'siparis_urun_unique'
);
SET @sql := IF(
  @idx_pair = 0,
  'ALTER TABLE `supply_orders` ADD UNIQUE KEY `siparis_urun_unique` (`siparis_no`,`urun_adi`(191))',
  'SELECT 1'
);
PREPARE stmt FROM @sql;
EXECUTE stmt;
DEALLOCATE PREPARE stmt;

  `siparis_no`, `kayit_tarihi`, `musteri_adi`, `telefon`, `adres`, `ilce`, `il`,
  `urun_adi`, `kategori`, `adet`, `soz_tarihi`, `renk_etiketi`, `durum`,
  `sebebiyet`, `gonderim_tarihi`, `notlar`, `created_at`, `updated_at`
)
SELECT
  s.`siparis_no`,
  s.`kayit_tarihi`,
  s.`musteri_adi`,
  s.`telefon`,
  s.`adres`,
  s.`ilce`,
  s.`il`,
  s.`urun_adi`,
  s.`kategori`,
  CASE
    WHEN s.`adet` IS NULL OR s.`adet` < 1 THEN 1
    WHEN s.`adet` > 65535 THEN 65535
    ELSE s.`adet`
  END AS `adet`,
  s.`soz_tarihi`,
  s.`renk_etiketi`,
  CASE
    WHEN s.`durum` IN ('bekliyor', 'uretim', 'paketleme', 'kargo', 'gonderildi') THEN s.`durum`
    ELSE 'bekliyor'
  END AS `durum`,
  CASE
    WHEN s.`sebebiyet` IN ('uretim', 'paketleme', 'kargo', 'yok') THEN s.`sebebiyet`
    ELSE 'yok'
  END AS `sebebiyet`,
  s.`gonderim_tarihi`,
  s.`notlar`,
  s.`created_at`,
  s.`updated_at`
FROM `_v05_supply_orders_src` s
LEFT JOIN `supply_orders` so
  ON so.`siparis_no` = s.`siparis_no`
 AND so.`urun_adi` = s.`urun_adi`
WHERE so.`id` IS NULL;

-- ------------------------------
-- 6) Temizlik + commit
-- ------------------------------
DROP TEMPORARY TABLE IF EXISTS `tmp_report_map`;
DROP TEMPORARY TABLE IF EXISTS `tmp_profile_map`;
DROP TABLE IF EXISTS `_v05_report_files_src`;
DROP TABLE IF EXISTS `_v05_reports_src`;
DROP TABLE IF EXISTS `_v05_profiles_src`;
DROP TABLE IF EXISTS `_v05_supply_orders_src`;

COMMIT;

SET SQL_NOTES = @OLD_SQL_NOTES;
SET FOREIGN_KEY_CHECKS = @OLD_FOREIGN_KEY_CHECKS;
SET UNIQUE_CHECKS = @OLD_UNIQUE_CHECKS;

-- Script sonu
